EXECUTION_MODE = "mcp_stdio"
MCP_SERVER_COMMAND = os.getenv("MCP_SERVER_COMMAND", "python")
MCP_SERVER_SCRIPT = os.getenv("MCP_SERVER_SCRIPT", "phishing_mcp_server.py")
REQUEST_TIMEOUT = int(os.getenv("UI_REQUEST_TIMEOUT", "120"))
APP_TITLE = "Phishing Simulation Analytics Copilot"

st.set_page_config(page_title=APP_TITLE, page_icon="🛡️", layout="wide", initial_sidebar_state="expanded")

